SELECT dataset_name, num_records
FROM datasets
ORDER BY num_records DESC;

SELECT dataset_id 
FROM datasets 
WHERE date_added = (SELECT MAX(date_added) FROM datasets);

SELECT COUNT(DISTINCT user_id) AS unique_users_accessed
FROM access_logs
WHERE dataset_id = (SELECT dataset_id FROM datasets WHERE dataset_name = 'ptobs');

SELECT COUNT(DISTINCT dataset_id) AS total_unique_datasets_accessed
FROM access_logs
WHERE access_date >= DATE('now', '-30 days');

SELECT dataset_name, num_records
FROM datasets
WHERE published = 1;
